class MyCircularQueue:
    def __init__(self, k):
        self.cap = k
        self.buf = [0] * k
        self.head = 0
        self.count = 0
    def enQueue(self, value):
        if self.count == self.cap:
            return False
        self.buf[(self.head + self.count) % self.cap] = value
        self.count += 1
        return True
    def deQueue(self):
        if self.count == 0:
            return False
        self.head = (self.head + 1) % self.cap
        self.count -= 1
        return True
    def Front(self):
        if self.count == 0:
            return -1
        return self.buf[self.head]
    def Rear(self):
        if self.count == 0:
            return -1
        return self.buf[(self.head + self.count - 1) % self.cap]
    def isEmpty(self):
        return self.count == 0
    def isFull(self):
        return self.count == self.cap

